#[test]
fn seal_handles_domain_endpoints() {
    let b = U32COSetBuilder::new();

    b.insert(iv(u32::MIN, u32::MIN + 1));
    b.insert(iv(2, 3));
    b.insert(iv(u32::MAX - 1, u32::MAX));

    let set = b.seal();

    assert_eq!(
        set.as_slice(),
        &[iv(u32::MIN, u32::MIN + 1), iv(2, 3), iv(u32::MAX - 1, u32::MAX)]
    );
}

#[test]
fn concurrent_writes_are_collected_before_seal() {
    let b = U32COSetBuilder::new();

    std::thread::scope(|s| {
        let b0 = &b;
        s.spawn(move || {
            b0.insert(iv(0, 4));
            b0.insert(iv(20, 25));
        });

        let b1 = &b;
        s.spawn(move || {
            b1.insert(iv(4, 8));
            b1.insert(iv(25, 30));
        });

        let b2 = &b;
        s.spawn(move || {
            b2.insert(iv(8, 10));
            b2.insert(iv(30, 31));
        });
    });

    let set = b.seal();

    assert_eq!(set.as_slice(), &[iv(0, 10), iv(20, 31)]);
}

use int_interval::U32CO;
use proptest::prelude::*;

fn reference_normalize(mut xs: Vec<(u32, u32)>) -> Vec<U32CO> {
    xs.sort_unstable();

    let mut out: Vec<int_interval::U32CO> = Vec::new();

    for (start, end_excl) in xs {
        let iv = iv(start, end_excl);

        match out.last_mut() {
            Some(last) if last.is_contiguous_with(iv) => {
                *last = last.convex_hull(iv);
            }
            _ => out.push(iv),
        }
    }

    out
}

proptest! {
    #[test]
    fn prop_seal_matches_reference_normalize(
        xs in prop::collection::vec(interval_pair(), 0..64)
    ) {
        let b = U32COSetBuilder::new();

        for &(start, end_excl) in &xs {
            b.insert(iv(start, end_excl));
        }

        let set = b.seal();
        let expected = reference_normalize(xs);

        prop_assert_eq!(set.as_slice(), expected.as_slice());
    }

    #[test]
    fn prop_seal_output_is_canonical(
        xs in prop::collection::vec(interval_pair(), 0..64)
    ) {
        let b = U32COSetBuilder::new();

        for (start, end_excl) in xs {
            b.insert(iv(start, end_excl));
        }

        let set = b.seal();

        prop_assert!(
            set.as_slice()
                .windows(2)
                .all(|w| w[0].end_excl() < w[1].start())
        );
    }
}
